changeSet.sql:
ALTER TABLE digitaltwinapp.currencies ADD COLUMN is_fiat  BOOLEAN      NOT NULL DEFAULT false;
ALTER TABLE digitaltwinapp.currencies ADD COLUMN logo_url VARCHAR(200);

UPDATE digitaltwinapp.currencies SET is_fiat = true  WHERE code IN ('USD', 'BRL');
UPDATE digitaltwinapp.currencies SET logo_url = 'assets/Circle_USDC_Logo.svg.png' WHERE code = 'USDC';
UPDATE digitaltwinapp.currencies SET logo_url = 'assets/tether-usdt-logo.svg'     WHERE code = 'USDT';
